mapper.select:
select ifnull(sum(estimated_income), 0) as estimatedIncome, ifnull(sum(order_num), 0) as orderNum,
    ifnull(sum(order_price), 0) as orderPrice, ifnull(sum(new_customer),0) as newCustomer, ifnull(sum(new_invitation),0) as newInvitation
from lkt_distribution_income

    store_id = #{storeId}
    and user_id = #{userId}
      and DATE_FORMAT(add_time,"%Y-%m-%d") = #{day}
      and DATE_FORMAT(add_time,"%Y-%m") = #{Month}
      and DATE_FORMAT(add_time,"%Y-%m-%d")   >=    #{startTime}
        and DATE_FORMAT(add_time,"%Y-%m-%d")   <=    #{endTime}
